jax({            url: "{{ route('consultationFormSave') }}",            type: 'POST',            data: {                "_token": "{{ csrf_token() }}",                first_name: first_name,                last_name: last_name,                email: email,                mobile: mobile,                clinic: clinic,                service: service,                message: message            },            beforeSend: function(res) {                //$('#state').html('<option value="">Loading...</option>');            },            success: function(res) {                if(res.status=='success'){                    $('#first_name').val('');                    $('#last_name').val('');                    $('#email').val('');                    $('#mobile').val('');                    $('#clinic').val('');                    $('#service').val('');                    $('#message').val('');                                        $('#subitMessage').html('<div id="alertMessage" class="alert alert-success" role="alert">Form submitted successfully!</div>');                }else{                    $('#subitMessage').html('<div id="alertMessage" class="alert alert-danger" role="alert">Something went wrong!</div>');                  }            }        })    }    </script>  @endsection